class Solution:
    def popcountDepth(self, nums, queries):
        def depth(x):
            d = 0
            while x != 1:
                x = bin(x).count('1')
                d += 1
            return d
        n = len(nums)
        B = 8
        trees = [[0] * (n + 1) for _ in range(B)]
        def upd(t, i, v):
            i += 1
            while i <= n:
                t[i] += v
                i += i & (-i)
        def qpre(t, i):
            i += 1
            s = 0
            while i > 0:
                s += t[i]
                i -= i & (-i)
            return s
        cur = [0] * n
        for j in range(n):
            d = depth(nums[j])
            cur[j] = d
            if d < B:
                upd(trees[d], j, 1)
        out = []
        for q in queries:
            if q[0] == 1:
                _, l, r, k = q
                if k < 0 or k >= B:
                    out.append(0)
                else:
                    t = trees[k]
                    res = qpre(t, r) - (qpre(t, l - 1) if l > 0 else 0)
                    out.append(res)
            else:
                _, idx, val = q
                old = cur[idx]
                if old < B:
                    upd(trees[old], idx, -1)
                nd = depth(val)
                cur[idx] = nd
                if nd < B:
                    upd(trees[nd], idx, 1)
        return out

