var popcountDepth = function(nums, queries) {
    const pc = (x) => { let c = 0n; let y = BigInt(x); while (y > 0n) { c += y & 1n; y >>= 1n; } return Number(c); };
    const depth = (x) => { let d = 0; let v = BigInt(x); while (v !== 1n) { v = BigInt(pc(v)); d++; } return d; };
    const n = nums.length;
    const B = 8;
    const trees = Array.from({ length: B }, () => new Array(n + 1).fill(0));
    const upd = (t, i, v) => { i += 1; while (i <= n) { t[i] += v; i += i & (-i); } };
    const qpre = (t, i) => { i += 1; let s = 0; while (i > 0) { s += t[i]; i -= i & (-i); } return s; };
    const cur = new Array(n).fill(0);
    for (let j = 0; j < n; j++) {
        const d = depth(nums[j]);
        cur[j] = d;
        if (d < B) upd(trees[d], j, 1);
    }
    const out = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1], r = q[2], k = q[3];
            if (k < 0 || k >= B) { out.push(0); continue; }
            const t = trees[k];
            const res = qpre(t, r) - (l > 0 ? qpre(t, l - 1) : 0);
            out.push(res);
        } else {
            const idx = q[1], val = q[2];
            const old = cur[idx];
            if (old < B) upd(trees[old], idx, -1);
            const nd = depth(val);
            cur[idx] = nd;
            if (nd < B) upd(trees[nd], idx, 1);
        }
    }
    return out;
};
